async function processInBatches(items, batchSize) {
  const results = [];

  for (let i = 0; i < items.length; i += batchSize) {
    // Slice out a chunk of items
    const chunk = items.slice(i, i + batchSize);

    // Map chunk to Promises
    const promises = chunk.map(item => fetch(`/api/process/${item}`));

    // Wait for this chunk to finish BEFORE starting the next one
    console.log(`Processing batch ${i / batchSize + 1}...`);
    const chunkResults = await Promise.all(promises);

    results.push(...chunkResults);
  }

  return results;
}

// Usage: process 100 items, but only 5 at a time.
// processInBatches(arrayOf100Items, 5);

